import React, { useEffect, useState, useCallback } from 'react';
import './MaterialList.css';
import EditMaterial from './EditMaterial';
import AddMaterial from './AddMaterial';

const MaterialList = () => {
  const [materials, setMaterials] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('http://localhost:8081/MaterialList');
        const data = await response.json();
        setMaterials(data);
      } catch (error) {
        console.log('Error fetching data:', error);
      }
    };

    fetchData();
  }, []);

  const handleDelete = useCallback((deletedMaterial) => {
    const confirmDeletion = window.confirm('Are you sure you want to delete this material?');

    if (confirmDeletion) {
      fetch(`http://localhost:8081/MaterialList/${deletedMaterial.matid}`, {
        method: 'DELETE',
      })
        .then((response) => response.json())
        .then((data) => {
          const updatedMaterialList = materials.filter((m) => m.matid !== deletedMaterial.matid);
          setMaterials(updatedMaterialList);
        })
        .catch((error) => {
          console.log('Error deleting material:', error);
        });
    }
  }, [materials]);

  const handleEdit = useCallback((material) => {
    setEditingMaterial(material);
  }, []);

  const handleAdd = useCallback((newMaterial) => {
    fetch('http://localhost:8081/MaterialList', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newMaterial),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding material');
        }
      })
      .then((data) => {
        const updatedMaterialList = [...materials, data];
        setMaterials(updatedMaterialList);
      })
      .catch((error) => {
        console.log('Error adding material:', error);
      });
  }, [materials]);

  const handleUpdate = useCallback((updatedMaterial) => {
    fetch(`http://localhost:8081/MaterialList/${updatedMaterial.matid}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(updatedMaterial),
    })
      .then((response) => response.json())
      .then((data) => {
        const updatedMaterialList = materials.map((m) =>
          m.matid === updatedMaterial.matid ? updatedMaterial : m
        );
        setMaterials(updatedMaterialList);
        setEditingMaterial(null);
      })
      .catch((error) => {
        console.log('Error updating material:', error);
      });
  }, [materials]);

  // Calculate pagination values
  const lastIndex = currentPage * pageSize;
  const firstIndex = lastIndex - pageSize;
  const paginatedMaterials = materials.slice(firstIndex, lastIndex);

  const totalPages = Math.ceil(materials.length / pageSize);

  // Handle pagination button clicks
  const goToPage = (pageNumber) => {
    setCurrentPage(pageNumber);
  };

  const previousPage = () => {
    if (currentPage > 1) {
      setCurrentPage((prevPage) => prevPage - 1);
    }
  };

  const nextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage((prevPage) => prevPage + 1);
    }
  };

  if (materials.length === 0) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <table className="material-table">
        {/* Render table rows for the current page */}
        <tbody>
          {paginatedMaterials.map((material) => (
            <tr key={material.matid}>
              <td>{material.matid}</td>
              <td>{material.name}</td>
              <td>{material.description}</td>
              <td>{material.unit_of_measure}</td>
              <td>{`${material.price_per_unit} €`}</td>
              <td>{material.recent_vendor}</td>
              <td>
                <div>
                  <button onClick={() => handleEdit(material)}>Edit</button>
                  <button onClick={() => handleDelete(material)}>Delete</button>
                </div>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      
      {/* Pagination buttons */}
      <div className="pagination">
        <button onClick={previousPage} disabled={currentPage === 1}>Previous</button>
        {Array.from({ length: totalPages }, (_, index) => (
          <button
            key={index + 1}
            onClick={() => goToPage(index + 1)}
            className={currentPage === index + 1 ? 'active' : ''}
          >
            {index + 1}
          </button>
        ))}
        <button onClick={nextPage} disabled={currentPage === totalPages}>Next</button>
      </div>

      <AddMaterial handleAdd={handleAdd} />
    </div>
  );
};

export default MaterialList;
